#include <iostream>
using namespace std;

int main() {
    long long p, ap, q, aq, N;
    cin >> p >> ap;
    cin >> q >> aq;
    cin >> N;

    // d = (aq - ap) / (q - p)
    long long d = (aq - ap) / (q - p);
    long long an = ap + (N - p) * d;
    cout << an << endl;

    return 0;
}
